// This phase ships TWO decisive ratios (distal femoral W/L, tibial IIOC
// H/W) rather than one, so the banner/values loop over the whole array
// instead of the single decisive[0] most other phases use. `decisive`
// (singular, first entry) is kept for any code path that only needs one.
var decisiveList = EV && Array.isArray(EV.decisive) ? EV.decisive.filter(Boolean) : [];
var decisive = decisiveList.length ? decisiveList[0] : null;
var HAS_EVIDENCE = decisiveList.length > 0;

