<script>
// ═══════════════════════════════════════════════════════════════════════════
// PER-PHASE ADDITION (not template-owned): the CC pre-flight gate, the
// reproducibility cross-check, a known stale-field discrepancy, and an
// inter-run consistency note (REVIEW_EVIDENCE.structural) aren't rendered by
// the template's evidence banner or Values tab, so this surfaces them as
// plain text in #structure-notes rather than leaving the reviewer with only
// "trust the numbers". Read-only: textContent only, no innerHTML, no eval, no
// network, no export/navigation — same trust boundary as the core script.
(function () {
  "use strict";
  var EV = window.REVIEW_EVIDENCE || {};
  var st = EV.structural;
  var el = document.getElementById("structure-notes");
  if (!el || !st) return;

  var parts = [];
  if (st.segmentation_cc) {
    parts.push("Pre-flight CC gate: femur=" + st.segmentation_cc.femur + ", tibia=" + st.segmentation_cc.tibia + " component(s) — PASS");
  }
  if (st.reproducibility) {
    parts.push("Reproducibility: " + st.reproducibility.status + " — " + st.reproducibility.note);
  }
  if (st.known_discrepancy) {
    parts.push("Known discrepancy in " + st.known_discrepancy.field + " (value " + st.known_discrepancy.value + "): " + st.known_discrepancy.correct_value_note + " " + st.known_discrepancy.note);
  }
  if (st.inter_run_note) {
    parts.push("Inter-run note: " + st.inter_run_note);
  }
  el.textContent = "";
  parts.forEach(function (p, i) {
    if (i > 0) el.appendChild(document.createTextNode("  •  "));
    el.appendChild(document.createTextNode(p));
  });
})();
</script>
